"""
Скрипт добавления задания 6 ЕГЭ база «Выбор оптимального варианта».

Условия с изображениями автоматически очищаются от текстовой расшифровки таблиц:
таблица остаётся только в PNG, а в тексте сохраняются вводная часть и вопрос.
Номер задания в текст вопроса не добавляется, чтобы пользователю отправлялось только условие.

Изображения должны соответствовать конкретному заданию, а не странице PDF.
Папка с изображениями:
    C:\\MY\\VK_BOT2.0\\app\\images_b\\n6

Имена файлов:
    task_001.png ... task_096.png
    task_116.png ... task_159.png

Для заданий, где в условии две таблицы, нужны два изображения, они будут
отправлены подряд через image_path с разделителем "|":
    task_093_table1.png, task_093_table2.png
    task_094_table1.png, task_094_table2.png
    task_095_table1.png, task_095_table2.png
    task_096_table1.png, task_096_table2.png
    task_144_table1.png, task_144_table2.png
    task_145_table1.png, task_145_table2.png
    task_146_table1.png, task_146_table2.png
    task_147_table1.png, task_147_table2.png

Задания 97–115 не требуют изображений: все данные есть в тексте.

Запуск:
    python add_eb06.py
"""

import asyncio
import aiosqlite
import os
import re

_dir = os.path.dirname(os.path.abspath(__file__))
BASE_DIR = os.path.dirname(_dir)
DB_PATH = os.path.join(BASE_DIR, "app", "bot_database.db")

EXAM_TYPE = "ege_base"
TASK_NUMBER = 6
TOPIC = "ege_b06_optimal"
IMAGE_DIR = os.path.join(BASE_DIR, "app", "images_b", "n6")

TASKS: list[tuple[str, str, str | None, str]] = []


def image_file(name: str | None) -> str | None:
    if not name:
        return None
    parts = [part.strip() for part in name.split("|") if part.strip()]
    return "|".join(os.path.join(IMAGE_DIR, part) for part in parts)


def strip_embedded_table_text(q: str) -> str:
    """
    Убирает из условия текстовую расшифровку таблицы, если таблица уже дана
    отдельным изображением. Оставляет вводную часть и сам вопрос.
    """
    lines = [line.strip() for line in q.strip().splitlines()]
    result: list[str] = []

    table_start_prefixes = (
        "номер", "название", "модель", "фирма", "предмет",
        "таблица 1", "таблица 2", "тарифный план", "поставщик",
        "перевозчик", "автомобиль", "салон", "интернет-", "к*",
    )

    question_start_prefixes = (
        "алексей хочет", "вадиму", "владлену", "игорю",
        "по правилам", "похвальные грамоты", "сергей петрович считает",
        "дмитрий валентинович хочет", "любовь игнатьевна хочет",
        "найдите", "какие", "пользуясь таблицей", "виталию нужно",
        "выберите", "во сколько", "сколько рублей", "определите",
        "*к", "итоговый балл", "пользователь предполагает",
        "абонент предполагает", "помимо аренды", "в ответе", "в ответ",
    )

    skipping_table = False

    for line in lines:
        low = line.lower().replace("ё", "е")

        if not skipping_table and any(low.startswith(p) for p in table_start_prefixes):
            skipping_table = True
            continue

        if skipping_table:
            if any(low.startswith(p.replace("ё", "е")) for p in question_start_prefixes):
                skipping_table = False
                result.append(line)
            continue

        result.append(line)

    cleaned = "\n".join(result)
    cleaned = re.sub(r"\n{3,}", "\n\n", cleaned).strip()
    return cleaned


def add(q: str, a: str, image_name: str | None = None) -> None:
    if image_name:
        q = strip_embedded_table_text(q)
    TASKS.append((q.strip(), a.strip(), image_file(image_name), TOPIC))


